[doc("the command invoked when just is run without arguments")]
default:
    @just --list

[doc("clean the build artifacts of xtask itself")]
xtask-clean:
    @cd scripts/xtask && cargo clean

[doc("run an xtask command, e.g. `just xtask help`")]
xtask *args:
    @cd scripts/xtask && cargo run -q -- {{ args }}

[doc("clean the build artifacts of Anemone kernel")]
clean:
    @just xtask clean

[doc("clean the build artifacts of Anemone kernel, including the configuration files")]
mrproper:
    @just xtask mrproper
    @rm -f disk.img

[doc("build Anemone kernel")]
build:
    @just xtask build

[doc("format Rust sources. optionally pass `kernel` or an app name")]
fmt *args:
    @just xtask fmt {{ args }}

[doc("manage configurations. type `just conf -h` for more details.")]
conf *args:
    @just xtask conf {{ args }}

[doc("app related commands. type `just app -h` for more details.")]
app *args:
    @just xtask app {{ args }}

[doc("rootfs management. type `just rootfs -h` for more details.")]
rootfs *args:
    @just xtask rootfs {{ args }}

[doc("generate the kconfig file from .defconfig")]
defconfig:
    @just log "DEFCONFIG" "Copying .defconfig to kconfig"
    @cp conf/.defconfig ./kconfig

[doc("generate an empty disk image")]
gendisk size:
    @just log "GENDISK" "Generating disk image"
    @rm -f disk.img
    @fallocate -l {{ size }} disk.img

[private]
log topic msg:
    @printf "  \\033[1;96m%10s\\033[0m \\033[1;m%s\\033[0m\\n" "{{ topic }}" "{{ msg }}"

use crate::prelude::*;

pub mod link_symbols;

unsafe fn clear_bss() {
    unsafe {
        use link_symbols::*;
        let bss_size_bytes =
            (__ebss as *const () as usize) - (__bss_zero_start as *const () as usize);
        let bss_start = __bss_zero_start as *mut u8;
        for i in 0..bss_size_bytes {
            bss_start.add(i).write_volatile(0);
        }
    };
}

macro_rules! arch_select {
    ($arch:ident, $arch_str:literal) => {
        #[cfg(target_arch = $arch_str)]
        mod $arch;
        #[cfg(target_arch = $arch_str)]
        pub use $crate::arch::$arch::{
            BacktraceArch, CpuArch, IntrArch, KernelLayout, PagingArch, SchedArch, SignalArch,
            TimeArch, TrapArch, machine_init,
        };
    };
}

arch_select!(riscv64, "riscv64");
arch_select!(loongarch64, "loongarch64");
