    fn mounted_superblocks_for(tree: &MountTree) -> Vec<Arc<SuperBlock>> {
        let mounts = tree.mounts();
        let mut superblocks = Vec::new();

        for mount in mounts.iter() {
            let sb = mount.sb().clone();
            if superblocks
                .iter()
                .any(|existing| Arc::ptr_eq(existing, &sb))
            {
                continue;
            }
            superblocks.push(sb);
