pub mod user_access;

const INVALID_SYSCALL: SyscallHandler = SyscallHandler {
    sysno: 0,
    nargs: 0,
    name: "invalid",
    handler: |_, _| Err(SysError::NoSys),
};

/// Syscall handler table. Singleton instance.
#[derive(Debug)]
struct SyscallTable {
    handlers: [SyscallHandler; ANEMONE_SYSNO_MAX as usize],
}

static SYSCALL_TABLE: MonoOnce<SyscallTable> = unsafe {
    MonoOnce::from_partial_initialized(SyscallTable {
        handlers: [INVALID_SYSCALL; ANEMONE_SYSNO_MAX as usize],
    })
};

pub fn register_syscall_handlers() {
    SYSCALL_TABLE.init(|s| {
        use link_symbols::{__esyscall, __ssyscall};

        let handlers = unsafe {
            let (start, end) = (
                __ssyscall as *const () as usize,
                __esyscall as *const () as usize,
            );
            assert!(start.is_multiple_of(align_of::<SyscallHandler>()));
            assert!((end - start).is_multiple_of(size_of::<SyscallHandler>()));
            let handler_count = (end - start) / size_of::<SyscallHandler>();
            core::slice::from_raw_parts(start as *const SyscallHandler, handler_count)
        };

        let handler_ptr = s.as_mut_ptr().cast::<SyscallHandler>();

        for handler in handlers {
            unsafe {
                assert!(handler.sysno < ANEMONE_SYSNO_MAX as usize);

                let h = &*handler_ptr.add(handler.sysno);

                if h.sysno != 0 {
                    panic!(
                        "duplicate syscall number {} for handlers {} and {}",
                        handler.sysno, h.name, handler.name,
                    );
                }

                knoticeln!(
                    "registering syscall handler {} for syscall number {}",
                    handler.name,
                    handler.sysno
                );

                handler_ptr.add(handler.sysno).write(*handler);
            }
        }
    });
}

/// System call handler.
///
/// For syscall occurring in kernel space, arch-specific code should just panic
/// immediately, and this function should never be called.
pub fn handle_syscall(trapframe: &mut TrapFrame) -> Option<RestartSyscall> {
    let sysno = trapframe.syscall_no();

    let handler = SYSCALL_TABLE
        .get()
        .handlers
        .get(sysno)
        .copied()
        .unwrap_or(INVALID_SYSCALL);

    if sysno < ANEMONE_SYSNO_MAX as usize && handler.sysno == 0 {
        kerrln!(
            "unknown syscall number {} from {}",
            sysno,
            current_task_id()
        );
    }

    let regs = SyscallRegs {
        sysno,
        args: [
            trapframe.syscall_arg::<0>(),
            trapframe.syscall_arg::<1>(),
            trapframe.syscall_arg::<2>(),
            trapframe.syscall_arg::<3>(),
            trapframe.syscall_arg::<4>(),
            trapframe.syscall_arg::<5>(),
        ],
    };

    trapframe.advance_syscall_pc();

    let (retval, restart) = match (handler.handler)(&regs, trapframe) {
        Ok(retval) => (retval, None),
        Err(err) => {
            kdebugln!(
                "{} failed with error {:?} for task {}",
                handler.name,
                err,
                current_task_id(),
            );

            let retval = -(i64::from(err.as_errno())) as u64;
            let restart = if let SysError::RestartSyscall(restart) = err {
                Some(restart)
            } else {
                None
            };
            (retval, restart)
        },
    };

    trapframe.set_syscall_retval(retval);

    restart
}

//! Initcall mechanism, used to run initialization code at various stages of the
//! kernel boot process in a automatic and modular manner.

use crate::prelude::*;

/// Initcall levels, which determine when the initcall functions will be called
/// during initialization.
#[derive(Debug)]
#[repr(i8)]
pub enum InitCallLevel {
    /// Register filesystem drivers.
    Fs = 0,
    /// Register generic device drivers.
    Driver = 1,
    /// Physical devices are probed when devices are discovered. This state
    /// happens right after that, and is for those virtual devices that should
    /// be registered to various subsystems. (e.g. null, zero, random for char
    /// subsystem, ramdisk for block subsystem, etc.)
    ///
    /// In that sense, this can be considered as virtual device probing.
    ///
    /// Additionally, those pseudo filesystems may also create their inodes in
    /// this stage.
    Probe = 2,
    /// Late kernel services after filesystem / driver / probe init, kthreadd
    /// bootstrap, and all CPU local init. This is a generic boot window, not a
    /// kthread- or service-specific policy level.
    Late = 3,
}

#[derive(Debug)]
#[repr(C)]
pub struct InitCall {
    pub name: &'static str,
    pub level: InitCallLevel,
    pub init_fn: fn(),
}

fn collect_initcalls(level: InitCallLevel) -> &'static [InitCall] {
    use link_symbols::*;

    let (start, end) = match level {
        InitCallLevel::Fs => (
            __sinitcall_fs as *const () as usize,
            __einitcall_fs as *const () as usize,
        ),
        InitCallLevel::Driver => (
            __sinitcall_driver as *const () as usize,
            __einitcall_driver as *const () as usize,
        ),
        InitCallLevel::Probe => (
            __sinitcall_probe as *const () as usize,
            __einitcall_probe as *const () as usize,
        ),
        InitCallLevel::Late => (
            __sinitcall_late as *const () as usize,
            __einitcall_late as *const () as usize,
        ),
    };

    assert!(start.is_multiple_of(align_of::<InitCall>()));
    assert!((end - start).is_multiple_of(size_of::<InitCall>()));
    let initcall_size = core::mem::size_of::<InitCall>();
    let initcall_count = (end - start) / initcall_size;
    unsafe { core::slice::from_raw_parts(start as *const InitCall, initcall_count) }
}

/// Runs all initcalls of the specified level.
///
/// # Safety
///
/// Calling initcall functions may have arbitrary side effects, and may not be
/// safe to call at certain points during initialization. The caller must ensure
/// that it is safe to call the initcall functions at the time.
pub unsafe fn run_initcalls(level: InitCallLevel) {
    let initcalls = collect_initcalls(level);
    for initcall in initcalls {
        (initcall.init_fn)();
    }
}

