impl AsSie for IrqFlags {
    fn from_sie(sie: bool) -> Self {
        Self::new(if sie { 1 } else { 0 })
    }

    fn to_sie(self) -> bool {
        #[cfg(debug_assertions)]
        {
            assert!(
                matches!(self.raw(), 0 | 1),
                "Invalid IrqFlags value: {}",
                self.raw()
            );
        }
        self.raw() & 1 != 0
    }
