//! System call conventions and numbers.
//! Architecture-specific.

unsafe fn syscall_raw(
    sysno: u64,
    arg0: u64,
    arg1: u64,
    arg2: u64,
    arg3: u64,
    arg4: u64,
    arg5: u64,
) -> u64 {
    let ret: u64;
    unsafe {
        core::arch::asm!(
            "ecall",
            in("a7") sysno,
            in("a0") arg0,
            in("a1") arg1,
            in("a2") arg2,
            in("a3") arg3,
            in("a4") arg4,
            in("a5") arg5,
            lateout("a0") ret,
        );
    }
    ret
}

pub unsafe fn syscall(
    sysno: u64,
    arg0: u64,
    arg1: u64,
    arg2: u64,
    arg3: u64,
    arg4: u64,
    arg5: u64,
) -> Result<u64, Errno> {
    let res = unsafe { syscall_raw(sysno, arg0, arg1, arg2, arg3, arg4, arg5) };
    let res = res as i64;
    if res < 0 {
        Err(-res as i32)
    } else {
        Ok(res as u64)
    }
}

